+//----------------------------Identity-----------------------------------------
+Node* ConvL2DNode::Identity(PhaseGVN* phase) {
+  // Convert L2D(D2L(x)) => x when x is provably integral
+  return (in(1)->Opcode() == Op_ConvD2L && is_integral_fp(phase, in(1)->in(1)))
+    ? in(1)->in(1)
+    : this;
+}
