+    @Setup
+    public void setup() {
+        Random r = new Random(42);
+        ints = new int[DEFAULT_X_RANGE];
+        intDoubles = new double[DEFAULT_X_RANGE];
+        fracDoubles = new double[DEFAULT_X_RANGE];
+        mixedDoubles = new double[DEFAULT_X_RANGE];
