+            ints[i] = r.nextInt(10000);
+            intDoubles[i] = ints[i];
+            fracDoubles[i] = r.nextInt(10000) + 0.5;
+            mixedDoubles[i] = (i % 2 == 0) ? (double) r.nextInt(10000) : r.nextInt(10000) + 0.5;
+        }
+    }
